body.script:
        (function() {
          const GAME_URL = "https://cdn.jsdelivr.net/gh/un-zynq/singlefilegames/eaglercraft-1-12-2.html";
          const frame = document.getElementById('gameFrame');

          fetch(GAME_URL)
            .then(response => {
              if (!response.ok) {
                throw new Error(`HTTP ${response.status}`);
              }
              return response.text();
            })
            .then(htmlContent => {
              const blob = new Blob([htmlContent], { type: 'text/html' });
              const blobUrl = URL.createObjectURL(blob);
              frame.src = blobUrl;

              // Optioneel: blob URL vrijgeven als iframe eenmaal geladen is
              frame.onload = function() {
                URL.revokeObjectURL(blobUrl);
              };
            })
            .catch(error => {
              console.error("Fout bij laden van het spel:", error);
              // Toon foutmelding in de iframe
              frame.srcdoc = `
Fout bij laden van het spel.
Controleer je internetverbinding.`;
            });
        })();
